{
  "terms": [
    {
      "term": "Resistance (R)",
      "simpleDefinition": "The total opposition that a specific component or circuit offers to the flow of electric current, measured in Ohms (Ω).",
      "anchor": "Think of it as the total 'friction' in a specific length of pipe.",
      "misconception": "Believing resistance is only about the material, ignoring that length and thickness also change it."
    },
    {
      "term": "Resistivity (ρ)",
      "simpleDefinition": "The inherent property of a material that determines how strongly it opposes current, regardless of its shape or size.",
      "anchor": "The 'DNA' of a material; copper has low resistivity, while rubber has very high resistivity.",
      "misconception": "Thinking resistivity changes if you cut a wire in half; the resistance changes, but the resistivity stays the same."
    },
    {
      "term": "Voltage Drop",
      "simpleDefinition": "The loss of electrical pressure (voltage) as current flows through a resistance.",
      "anchor": "The drop in water pressure you see at the end of a very long garden hose.",
      "misconception": "Assuming voltage drop only happens when something is broken; it happens in every working circuit."
    },
    {
      "term": "Ohm (Ω)",
      "simpleDefinition": "The unit of measurement for electrical resistance.",
      "anchor": "The standard 'score' for how much a component fights current.",
      "misconception": "Confusing the symbol for Ohms (Ω) with the unit for resistivity (Ωm)."
    },
    {
      "term": "Ohm-metre (Ωm)",
      "simpleDefinition": "The unit of measurement for resistivity.",
      "anchor": "The measurement of a material's resistance based on a standard 1-metre cube.",
      "misconception": "Using 'Ohms' when you should be using 'Ohm-metres' to describe a material property."
    }
  ],
  "anchorPhrases": [
    "Resistance is the total opposition to current flow.",
    "Resistivity is a fixed property of the material itself.",
    "Voltage drop is the reduction in electrical potential.",
    "Higher resistivity leads to higher resistance for the same size conductor.",
    "Voltage is 'used up' pushing current through resistance."
  ],
  "misconceptionTargets": [
    "Resistivity and resistance are interchangeable terms.",
    "Voltage drop is always a sign of a fault.",
    "Changing the length of a cable changes its resistivity.",
    "Voltage remains constant throughout the entire length of a conductor."
  ]
}

{
  "teachChecks": [
    {
      "title": "Understanding Resistance",
      "basicQuestions": [
        {
          "questionText": "What term describes the total opposition to the flow of electric current in a circuit?",
          "answerGuidance": [
            "Resistance",
            "Electrical resistance"
          ],
          "hint": "Think of the total 'friction' the current faces.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the unit of measurement for electrical resistance?",
          "answerGuidance": [
            "Ohm",
            "Ohms",
            "Ω"
          ],
          "hint": "This unit is represented by the Greek symbol Omega.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "If the resistance in a circuit increases while the voltage remains the same, what happens to the current flow?",
          "answerGuidance": [
            "Decreases",
            "It goes down",
            "Reduces"
          ],
          "hint": "Resistance opposes flow; more opposition means less movement.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "Why is it technically incorrect to say that resistance only exists within the appliances connected to a circuit?",
      "deeperAnswerGuidance": [
        "Resistance exists in every part of the circuit",
        "The copper conductors themselves have resistance",
        "Supply cables provide a level of opposition to current",
        "Resistance is not limited to the load or heater"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Consider the materials used to connect the appliances to the power source."
    },
    {
      "title": "Understanding Resistivity",
      "basicQuestions": [
        {
          "questionText": "What term refers to the inherent property of a material that determines its opposition to current regardless of its shape?",
          "answerGuidance": [
            "Resistivity",
            "ρ"
          ],
          "hint": "This is a fixed characteristic of the material itself.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP2"
          ]
        },
        {
          "questionText": "What is the specific unit of measurement used for resistivity?",
          "answerGuidance": [
            "Ohm-metre",
            "Ωm",
            "Ohm-meter"
          ],
          "hint": "It is different from the unit for total resistance.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Which Greek letter is used as the symbol for resistivity?",
          "answerGuidance": [
            "rho",
            "ρ"
          ],
          "hint": "It looks like a small, rounded 'p'.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "If you have two different-sized blocks of the same grade of copper, why is their resistivity identical even if their total resistance is different?",
      "deeperAnswerGuidance": [
        "Resistivity is a fixed characteristic of the material",
        "It does not depend on the shape or size of the object",
        "It is an inherent property like DNA",
        "Resistance changes with dimensions but resistivity is constant for that material"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Think about the difference between a material property and an object's physical dimensions."
    },
    {
      "title": "Resistance vs. Resistivity",
      "basicQuestions": [
        {
          "questionText": "If a copper cable is cut in half, what happens to the resistivity of the remaining copper?",
          "answerGuidance": [
            "Stays the same",
            "No change",
            "Remains constant"
          ],
          "hint": "Does the type of metal change when you cut it?",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "If a conductor is shortened, what happens to its total electrical resistance?",
          "answerGuidance": [
            "Decreases",
            "It gets lower",
            "Reduces"
          ],
          "hint": "Shorter paths offer less total opposition.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Between two wires of the same material and length, which one will have a higher resistance: the thin wire or the thick wire?",
          "answerGuidance": [
            "Thin wire",
            "The thin one"
          ],
          "hint": "Think about which path is harder for electrons to squeeze through.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "How does the concept of resistivity allow an electrician to compare the conductive quality of copper versus aluminum without knowing the length of the wires?",
      "deeperAnswerGuidance": [
        "Resistivity is the 'per unit' opposition of the material",
        "It provides a standard value for the material itself",
        "It allows comparison regardless of the physical dimensions",
        "It describes the natural ability to conduct based on the material type"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP4"
      ],
      "hint": "Focus on why we use a 'fixed characteristic' to compare different metals."
    },
    {
      "title": "The Concept of Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "What is the term for the reduction in electrical pressure as current flows through a resistance?",
          "answerGuidance": [
            "Voltage drop"
          ],
          "hint": "It is the loss of potential between the source and the load.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "How does the voltage measured at the end of a circuit compare to the voltage at the source?",
          "answerGuidance": [
            "Lower",
            "It is less",
            "Reduced"
          ],
          "hint": "Some pressure is 'used up' along the way.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Is voltage drop always an indication of a fault in the electrical system?",
          "answerGuidance": [
            "No",
            "False"
          ],
          "hint": "Consider if it is a natural consequence of current flowing through resistance.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why might a motor fail to start if the voltage drop in the supply cables is too high, even if the source voltage is correct?",
      "deeperAnswerGuidance": [
        "The motor is not receiving enough electrical pressure",
        "Voltage is lost overcoming the resistance of the cables",
        "The voltage at the load is too low for the equipment to operate",
        "The equipment runs inefficiently without its required potential"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP5"
      ],
      "hint": "Think about what the motor actually 'sees' at its terminals compared to the source."
    },
    {
      "title": "Resistivity's Impact on Voltage Drop",
      "basicQuestions": [
        {
          "questionText": "If two cables are the same size but one has higher resistivity, which cable will have the higher resistance?",
          "answerGuidance": [
            "Higher resistivity material",
            "The one with higher resistivity"
          ],
          "hint": "Resistivity directly determines the total resistance of the object.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What effect does an increase in a conductor's resistance have on the voltage drop across it for a set current?",
          "answerGuidance": [
            "Increases",
            "Larger voltage drop",
            "Higher drop"
          ],
          "hint": "More opposition requires more pressure to overcome.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Why is copper specifically chosen for electrical wiring to minimize voltage drop?",
          "answerGuidance": [
            "Low resistivity",
            "It has low resistivity"
          ],
          "hint": "Lower material opposition leads to lower resistance and less lost pressure.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "How does the choice of a high-resistivity material for a long cable run directly lead to energy being wasted as heat?",
      "deeperAnswerGuidance": [
        "High resistivity creates higher resistance",
        "Higher resistance causes a larger voltage drop",
        "Voltage is 'used up' pushing current through the material",
        "The lost electrical energy is converted into heat"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP3",
        "TP5"
      ],
      "hint": "Connect the material property to the resistance and then to the loss of electrical potential."
    }
  ]
}

{
  "integrative": {
    "title": "Linking Material to Performance",
    "objective": "Synthesize the relationship between a material's resistivity, the resulting resistance of a specific conductor, and the final voltage drop experienced by a load.",
    "retrievalTextLines": [
      "Resistivity is the fixed 'DNA' of the conductor material (e.g., copper).",
      "Resistance is the total opposition of the specific length and thickness of that conductor.",
      "Voltage drop is the loss of electrical potential as current overcomes that resistance."
    ],
    "questionText": "A 100-metre circuit is wired using copper conductors. Explain how the resistivity of the copper and the total resistance of this specific 100-metre run result in a measurable voltage drop at the end of the circuit.",
    "answerGuidance": [
      "Copper has a specific, fixed resistivity which is its inherent material property.",
      "The 100m length and the cable's thickness combine with that resistivity to create a total resistance (R).",
      "Electrical pressure (voltage) is required to push current through this total resistance.",
      "This 'work' results in a loss of potential, known as voltage drop, meaning less voltage is available at the load than at the source."
    ],
    "hint": "Start with the material's natural property, explain how the physical cable size turns that into a total 'friction' value, and describe what happens to the electrical pressure as it fights through it."
  }
}

